import React, { useState, useEffect } from 'react';

const App = () => {
  const [activeChannel, setActiveChannel] = useState(0);
  const [typingIndicators, setTypingIndicators] = useState([false, false, false]);

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#C06C88] p-4 rounded-md">
        <h2 className="text-2xl font-bold">Chat App</h2>
        <div className="flex justify-between gap-4 mt-4">
          <div className="bg-[#090a0f] p-2 rounded-md hover:bg-white hover:text-[#090a0f] cursor-pointer" onClick={() => setActiveChannel(0)}>#Chat</div>
          <div className="bg-[#090a0f] p-2 rounded-md hover:bg-white hover:text-[#090a0f] cursor-pointer" onClick={() => setActiveChannel(1)}>#Discussion</div>
          <div className="bg-[#090a0f] p-2 rounded-md hover:bg-white hover:text-[#090a0f] cursor-pointer" onClick={() => setActiveChannel(2)}>#Support</div>
        </div>
        <div className="flex flex-col gap-2 mt-4">
          {channels.map((channel, index) => (
            <div key={index} className="bg-[#B7D7CD] p-2 rounded-md" onMouseOver={() => setTypingIndicators(old => [...old, true])} onMouseOut={() => setTypingIndicators(old => old.map((indicator, i) => i === index ? false : indicator))}>{channel.name}</div>
          ))}
        </div>
        <div className="flex flex-col gap-2 mt-4">
          {typingIndicators.map((indicator, index) => (
            <div key={index} className={`bg-[#B7D7CD] p-2 rounded-md ${indicator ? 'animate-pulse' : ''}`}>{indicator ? 'Typing...' : ''}</div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default App;
